"""
Blocos por etapa: e o que faz cada aba da ficha ter conteudo proprio.

O BACK-FILL importa mais que os campos. Sem ele, toda etapa que ja existe fica
com `blocos=[]` e a aba nasce VAZIA, inclusive em producao. Casa pelo NOME com
as sete etapas padrao; etapa que o cliente criou (nome fora da lista) recebe o
conjunto minimo (anotacao mais mensagem), que serve pra qualquer coisa e nao
inventa comportamento que ninguem pediu.
"""
from django.db import migrations, models


def preencher_blocos(apps, schema_editor):
    from apps.people import estados_recrutamento as estados_rs

    Etapa = apps.get_model('people', 'EtapaPipeline')

    por_nome = {e['nome']: e for e in estados_rs.ETAPAS_PADRAO}
    minimo = [estados_rs.BLOCO_ANOTACAO, estados_rs.BLOCO_MENSAGEM]

    atualizadas = []
    for etapa in Etapa.objects.all():
        if etapa.blocos:
            continue
        padrao = por_nome.get(etapa.nome)
        etapa.blocos = padrao['blocos'] if padrao else minimo
        if estados_rs.BLOCO_ROTEIRO in etapa.blocos and not etapa.roteiro:
            etapa.roteiro = estados_rs.ROTEIRO_PADRAO
        if estados_rs.BLOCO_CHECKLIST in etapa.blocos and not etapa.checklist:
            etapa.checklist = estados_rs.CHECKLIST_PADRAO
        atualizadas.append(etapa)

    if atualizadas:
        Etapa.objects.bulk_update(atualizadas,
                                  ['blocos', 'roteiro', 'checklist'],
                                  batch_size=200)


